def fibonacci(n):
    """Genera los números de Fibonacci hasta la posición n."""
    anterior = 1
    trasanterior = 0
    resultado = [0, 1]

    # Si n es 0 o 1, se devuelve una porción del arreglo resultado
    if n == 0:
        return np.array([0])
    elif n == 1:
        return np.array([0, 1])

    for _ in range(n - 1):
        actual = anterior + trasanterior
        resultado.append(actual)

        # Actualizar los valores para la siguiente iteración
        anterior, trasanterior = actual, anterior

    return np.array(resultado)

